INSERT INTO articles (
  slug, title, subtitle, summary, content, excerpt, meta_description,
  image, image_alt, category_id, category_slug, subcategory_slug, tags,
  author_id, published_at, reading_time, views, comments_count, shares,
  is_breaking, is_featured, is_trending, source_id, source_url,
  ai_rewritten, original_language, status
)
SELECT
  d.slug, d.title, d.subtitle, d.summary, d.content, d.excerpt, d.meta_description,
  d.image, d.image_alt, c.id, d.category_slug, d.subcategory_slug, d.tags,
  a.id, d.published_at, d.reading_time, d.views, d.comments_count, d.shares,
  d.is_breaking, d.is_featured, d.is_trending, s.id, d.source_url,
  d.ai_rewritten, d.original_language, 'published'
FROM article_data d
LEFT JOIN categories c ON c.slug = d.category_slug
LEFT JOIN authors a ON a.name = d.author_name
LEFT JOIN sources s ON s.name = d.source_name
ON CONFLICT (slug) DO NOTHING;
